 16	import { QuestionCircleIcon, SyncAltIcon } from '@patternfly/react-icons';
 17	import * as React from 'react';
 18	import { useTranslation } from 'react-i18next';
 19	import { Config, defaultConfig } from '../../model/config';
 20	import { loadConfig } from '../../utils/config';
 21	import { getGenericHTTPError } from '../../utils/errors';
 22	import { localStorageHealthRefreshKey, useLocalStorage } from '../../utils/local-storage-hook';
 23	import { usePoll } from '../../utils/poll-hook';
 24	import { useTheme } from '../../utils/theme-hook';
 25	import { RefreshDropdown } from '../dropdowns/refresh-dropdown';
 26	import { HealthDrawerContainer } from './health-drawer-container';
 27	import HealthError from './health-error';
 28	import { fetchNetworkHealth } from './health-fetcher';
 29	import { HealthGlobal } from './health-global';
 30	import { buildStats, HealthStats } from './health-helper';
 31	import { HealthScoringDrawer } from './health-scoring-drawer';
 32	import { HealthSummary } from './health-summary';
 33	import { HealthTabTitle } from './tab-title';
 34	
 35	import './health.css';
 36	
 37	export const NetworkHealth: React.FC<{}> = ({}) => {
 38	  const { t } = useTranslation('plugin__netobserv-plugin');
 39	  const isDarkTheme = useTheme();
 40	  const [loading, setLoading] = React.useState(false);
 41	  const [error, setError] = React.useState<string | undefined>();
 42	  const [interval, setInterval] = useLocalStorage<number | undefined>(localStorageHealthRefreshKey, undefined);
 43	  const [rules, setRules] = React.useState<Rule[]>([]);
 44	  const [health, setHealth] = React.useState<HealthStats>(buildStats([]));
 45	  const [activeTabKey, setActiveTabKey] = React.useState<string>('global');
 46	  const [config, setConfig] = React.useState<Config>(defaultConfig);
 47	  const [configLoaded, setConfigLoaded] = React.useState(false);
 48	  const [isScoringDrawerOpen, setIsScoringDrawerOpen] = React.useState<boolean>(false);
 49	
 50	  // Load config on mount
 51	  React.useEffect(() => {
 52	    loadConfig().then(v => {
 53	      setConfig(v.config);
 54	      setConfigLoaded(true);
 55	      if (v.error) {
 56	        console.error('Error loading config:', v.error);
 57	      }
 58	    });
 59	  }, []);
 60	
 61	  const fetch = React.useCallback(() => {
 62	    setLoading(true);
 63	    setError(undefined);
 64	
 65	    fetchNetworkHealth(config.recordingAnnotations || {})
 66	      .then(res => {
 67	        setHealth(res.stats);
 68	        setRules(res.alertRules);
 69	      })
 70	      .catch(err => {
 71	        const errStr = getGenericHTTPError(err);
 72	        setError(errStr);
 73	      })
 74	      .finally(() => {
 75	        setLoading(false);
 76	      });
 77	  }, [config]);
 78	
 79	  usePoll(fetch, interval);
 80	  // Run first fetch only after config is loaded so recordingAnnotations (including third-party rules without template label) is available
 81	  React.useEffect(() => {
 82	    if (configLoaded) {
 83	      fetch();
 84	    }
 85	  }, [configLoaded, fetch]);
 86	
 87	  const panelContent = () => {
 88	    if (isScoringDrawerOpen) {
 89	      return <HealthScoringDrawer isOpen={isScoringDrawerOpen} onClose={() => setIsScoringDrawerOpen(false)} />;
 90	    }
 91	    return null;
 92	  };
 93	
 94	  const mainContent = () => {
 95	    return (
 96	      <div className="health-main-content">
 97	        {error ? (
 98	          <HealthError title={t('Error')} body={error} />
 99	        ) : (
100	          <>
101	            <Flex className={`health-tabs-container ${isDarkTheme ? 'dark' : ''}`}>
102	              <FlexItem flex={{ default: 'flex_1' }}>
103	                <Tabs
104	                  activeKey={activeTabKey}
105	                  onSelect={(_, tabIndex) => setActiveTabKey(String(tabIndex))}
106	                  role="region"
107	                  className={isDarkTheme ? 'dark' : ''}
108	                >
109	                  <Tab
110	                    eventKey={'global'}
111	                    title={<HealthTabTitle title={t('Global')} stats={[health.global]} />}
112	                    aria-label="Tab global"
113	                  />
114	                  <Tab
115	                    eventKey={'per-node'}
116	                    title={<HealthTabTitle title={t('Nodes')} stats={health.byNode} />}
117	                    aria-label="Tab per node"
118	                  />
119	                  <Tab
120	                    eventKey={'per-namespace'}
121	                    title={<HealthTabTitle title={t('Namespaces')} stats={health.byNamespace} />}
122	                    aria-label="Tab per namespace"
123	                  />
124	                  <Tab
125	                    eventKey={'per-owner'}
126	                    title={<HealthTabTitle title={t('Workloads')} stats={health.byOwner} />}
127	                    aria-label="Tab per owner"
128	                  />
129	                </Tabs>
130	              </FlexItem>
131	              <FlexItem className={'bottom-border'}>
132	                <Button
