134	                  className="overflow-button"
135	                  variant="link"
136	                  onClick={() => setIsScoringDrawerOpen(!isScoringDrawerOpen)}
137	                  icon={<QuestionCircleIcon />}
138	                >
139	                  {isScoringDrawerOpen ? t('Hide scoring information') : t('Show scoring information')}
140	                </Button>
141	              </FlexItem>
142	            </Flex>
143	            {activeTabKey === 'global' && <HealthGlobal info={health.global} isDark={isDarkTheme} />}
144	            {activeTabKey === 'per-node' && (
145	              <HealthDrawerContainer
146	                title={t('Rule violations per node')}
147	                stats={health.byNode}
148	                kind={'Node'}
149	                isDark={isDarkTheme}
150	              />
151	            )}
152	            {activeTabKey === 'per-namespace' && (
153	              <HealthDrawerContainer
154	                title={t('Rule violations per namespace')}
155	                stats={health.byNamespace}
156	                kind={'Namespace'}
157	                isDark={isDarkTheme}
158	              />
159	            )}
160	            {activeTabKey === 'per-owner' && (
161	              <HealthDrawerContainer
162	                title={t('Rule violations per workload')}
163	                stats={health.byOwner}
164	                kind={'Owner'}
165	                isDark={isDarkTheme}
166	              />
167	            )}
168	          </>
169	        )}
170	      </div>
171	    );
172	  };
173	
174	  return (
175	    <PageSection id="health-page" className={`${isDarkTheme ? 'dark' : 'light'}`}>
176	      <Drawer id="health-drawer" isInline isExpanded={isScoringDrawerOpen}>
177	        <DrawerContent id="healthDrawerContent" panelContent={panelContent()}>
178	          <DrawerContentBody id="healthDrawerBody">
179	            <Flex id="health-page-content-flex" direction={{ default: 'column' }}>
180	              <FlexItem className="health-header-container">
181	                <Flex className="health-header" direction={{ default: 'row' }}>
182	                  <FlexItem flex={{ default: 'flex_1' }}>
183	                    <Flex direction={{ default: 'column' }}>
184	                      <FlexItem>
185	                        <Title headingLevel={TextVariants.h1}>{t('Network Health')}</Title>
186	                      </FlexItem>
187	                      <FlexItem>
188	                        <HealthSummary rules={rules} stats={health} forceCollapsed={isScoringDrawerOpen} />
189	                      </FlexItem>
190	                    </Flex>
191	                  </FlexItem>
192	                  <FlexItem>
193	                    <Flex direction={{ default: 'row' }}>
194	                      <FlexItem className="netobserv-refresh-interval-container">
195	                        <Flex direction={{ default: 'column' }}>
196	                          <FlexItem className="netobserv-action-title">
197	                            <Text component={TextVariants.h4}>{t('Refresh interval')}</Text>
198	                          </FlexItem>
199	                          <FlexItem flex={{ default: 'flex_1' }}>
200	                            <RefreshDropdown
201	                              data-test="refresh-dropdown"
202	                              id="refresh-dropdown"
203	                              interval={interval}
204	                              setInterval={setInterval}
205	                            />
206	                          </FlexItem>
207	                        </Flex>
208	                      </FlexItem>
209	                      <FlexItem className="netobserv-refresh-container">
210	                        <Button
211	                          data-test="refresh-button"
212	                          id="refresh-button"
213	                          className="co-action-refresh-button"
214	                          variant="primary"
215	                          onClick={() => fetch()}
216	                          icon={<SyncAltIcon style={{ animation: `spin ${loading ? 1 : 0}s linear infinite` }} />}
217	                        />
218	                      </FlexItem>
219	                    </Flex>
220	                  </FlexItem>
221	                </Flex>
222	              </FlexItem>
223	              <FlexItem
224	                id="health-content-container"
225	                flex={{ default: 'flex_1' }}
226	                className={isDarkTheme ? 'dark' : 'light'}
227	              >
228	                {mainContent()}
229	              </FlexItem>
230	            </Flex>
231	          </DrawerContentBody>
232	        </DrawerContent>
233	      </Drawer>
234	    </PageSection>
235	  );
